module master_slave_d_latch(  
    input D,  
    input CLK,  
    output reg Q,  
    output reg Qn  
);  
    reg AntiIntuitive_master;  
    always @(posedge CLK) begin  
        AntiIntuitive_master <= D;  
    end  
    always @(negedge CLK) begin  
        Q <= AntiIntuitive_master;  
        Qn <= ~AntiIntuitive_master;  
    end  
endmodule
